import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { 
  User, 
  Calendar,
  Hash,
  Users,
  FileText,
  Plus,
  Trash2,
  Check,
  X
} from 'lucide-react';

const ClientForm = () => {
  const [formData, setFormData] = useState({
    clientNumber: '',
    clientName: '',
    hearingDate: '',
    riders: [{
      aNumber: '',
      name: '',
      isMinor: false
    }],
    additionalNotes: ''
  });

  const formatANumber = (value) => {
    const numbers = value.replace(/\D/g, '');
    const matches = numbers.match(/\d{1,3}/g);
    if (matches) {
      return matches.join('-').substr(0, 11);
    }
    return '';
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    if (name === 'clientNumber') {
      setFormData(prev => ({
        ...prev,
        [name]: formatANumber(value)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleRiderChange = (index, field, value) => {
    const updatedRiders = [...formData.riders];
    if (field === 'aNumber') {
      updatedRiders[index][field] = formatANumber(value);
    } else {
      updatedRiders[index][field] = value;
    }
    setFormData(prev => ({
      ...prev,
      riders: updatedRiders
    }));
  };

  const addRider = () => {
    setFormData(prev => ({
      ...prev,
      riders: [...prev.riders, { aNumber: '', name: '', isMinor: false }]
    }));
  };

  const removeRider = (index) => {
    if (formData.riders.length > 1) {
      setFormData(prev => ({
        ...prev,
        riders: prev.riders.filter((_, i) => i !== index)
      }));
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 via-gray-800 to-gray-900 p-6">
      <div className="max-w-5xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <motion.h1 
            initial={{ y: -20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            className="text-4xl font-bold text-white mb-4 tracking-tight"
          >
            Client Information
          </motion.h1>
          <div className="h-1 w-24 bg-gradient-to-r from-blue-500 to-indigo-600 mx-auto rounded-full"></div>
        </div>

        {/* Form */}
        <motion.form 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.2 }}
          onSubmit={handleSubmit}
          className="space-y-8"
        >
          {/* Client Info Card */}
          <div className="bg-gray-800/50 backdrop-blur-xl rounded-2xl p-8 shadow-xl border border-gray-700/50">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Client A# */}
              <div className="space-y-3">
                <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                  <Hash className="h-4 w-4 text-blue-400" />
                  Client A#
                </label>
                <div className="relative group">
                  <input
                    type="text"
                    name="clientNumber"
                    value={formData.clientNumber}
                    onChange={handleInputChange}
                    placeholder="123-456-789"
                    className="w-full bg-gray-900/50 border border-gray-700 text-gray-100 rounded-xl px-4 py-3
                             focus:ring-2 focus:ring-blue-500 focus:border-transparent
                             placeholder-gray-500 transition-all duration-200"
                  />
                  <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-500/20 to-indigo-500/20 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                </div>
              </div>

              {/* Client Name */}
              <div className="space-y-3">
                <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                  <User className="h-4 w-4 text-blue-400" />
                  Client Name
                </label>
                <div className="relative group">
                  <input
                    type="text"
                    name="clientName"
                    value={formData.clientName}
                    onChange={handleInputChange}
                    placeholder="Enter client name"
                    className="w-full bg-gray-900/50 border border-gray-700 text-gray-100 rounded-xl px-4 py-3
                             focus:ring-2 focus:ring-blue-500 focus:border-transparent
                             placeholder-gray-500 transition-all duration-200"
                  />
                  <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-500/20 to-indigo-500/20 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                </div>
              </div>

              {/* Hearing Date */}
              <div className="space-y-3">
                <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-blue-400" />
                  Hearing Date
                </label>
                <div className="relative group">
                  <input
                    type="date"
                    name="hearingDate"
                    value={formData.hearingDate}
                    onChange={handleInputChange}
                    className="w-full bg-gray-900/50 border border-gray-700 text-gray-100 rounded-xl px-4 py-3
                             focus:ring-2 focus:ring-blue-500 focus:border-transparent
                             placeholder-gray-500 transition-all duration-200"
                  />
                  <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-500/20 to-indigo-500/20 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                </div>
              </div>
            </div>
          </div>

          {/* Riders Section */}
          <div className="bg-gray-800/50 backdrop-blur-xl rounded-2xl p-8 shadow-xl border border-gray-700/50">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-semibold text-white flex items-center gap-2">
                <Users className="h-5 w-5 text-blue-400" />
                Riders
              </h2>
              <button
                type="button"
                onClick={addRider}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-xl
                         transition-all duration-200 transform hover:scale-105 active:scale-95"
              >
                <Plus className="h-4 w-4" />
                Add Rider
              </button>
            </div>

            <div className="space-y-6">
              {formData.riders.map((rider, index) => (
                <motion.div
                  key={index}
                  initial={{ x: -20, opacity: 0 }}
                  animate={{ x: 0, opacity: 1 }}
                  className="relative p-6 bg-gray-900/50 rounded-xl border border-gray-700/50 group"
                >
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {/* Rider A# */}
                    <div className="space-y-3">
                      <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                        <Hash className="h-4 w-4 text-blue-400" />
                        Rider A#
                      </label>
                      <input
                        type="text"
                        value={rider.aNumber}
                        onChange={(e) => handleRiderChange(index, 'aNumber', e.target.value)}
                        placeholder="123-456-789"
                        className="w-full bg-gray-800/50 border border-gray-700 text-gray-100 rounded-xl px-4 py-3
                                 focus:ring-2 focus:ring-blue-500 focus:border-transparent
                                 placeholder-gray-500 transition-all duration-200"
                      />
                    </div>

                    {/* Rider Name */}
                    <div className="space-y-3">
                      <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                        <User className="h-4 w-4 text-blue-400" />
                        Rider Name
                      </label>
                      <input
                        type="text"
                        value={rider.name}
                        onChange={(e) => handleRiderChange(index, 'name', e.target.value)}
                        placeholder="Enter rider name"
                        className="w-full bg-gray-800/50 border border-gray-700 text-gray-100 rounded-xl px-4 py-3
                                 focus:ring-2 focus:ring-blue-500 focus:border-transparent
                                 placeholder-gray-500 transition-all duration-200"
                      />
                    </div>

                    {/* Minor Checkbox */}
                    <div className="flex items-center justify-between">
                      <label className="flex items-center gap-3 cursor-pointer group">
                        <div className="relative">
                          <input
                            type="checkbox"
                            checked={rider.isMinor}
                            onChange={(e) => handleRiderChange(index, 'isMinor', e.target.checked)}
                            className="sr-only peer"
                          />
                          <div className="w-10 h-6 bg-gray-700 rounded-full peer peer-checked:after:translate-x-full 
                                        after:content-[''] after:absolute after:top-0.5 after:left-[2px] after:bg-white 
                                        after:rounded-full after:h-5 after:w-5 after:transition-all
                                        peer-checked:bg-blue-600"
                          ></div>
                        </div>
                        <span className="text-sm font-medium text-gray-300 group-hover:text-white transition-colors">Minor</span>
                      </label>

                      {formData.riders.length > 1 && (
                        <button
                          type="button"
                          onClick={() => removeRider(index)}
                          className="p-2 text-gray-400 hover:text-red-400 transition-colors rounded-lg
                                   hover:bg-red-400/10"
                        >
                          <Trash2 className="h-5 w-5" />
                        </button>
                      )}
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </div>

          {/* Additional Notes */}
          <div className="bg-gray-800/50 backdrop-blur-xl rounded-2xl p-8 shadow-xl border border-gray-700/50">
            <div className="space-y-3">
              <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                <FileText className="h-4 w-4 text-blue-400" />
                Additional Notes
              </label>
              <div className="relative group">
                <textarea
                  name="additionalNotes"
                  value={formData.additionalNotes}
                  onChange={handleInputChange}
                  rows="4"
                  placeholder="Enter any additional notes"
                  className="w-full bg-gray-900/50 border border-gray-700 text-gray-100 rounded-xl px-4 py-3
                           focus:ring-2 focus:ring-blue-500 focus:border-transparent
                           placeholder-gray-500 transition-all duration-200 resize-none"
                />
                <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-500/20 to-indigo-500/20 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
              </div>
            </div>
          </div>

          {/* Submit Button */}
          <div className="flex justify-end">
            <button
              type="submit"
              className="flex items-center gap-2 px-8 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 
                       hover:from-blue-700 hover:to-indigo-700 text-white rounded-xl font-medium
                       transition-all duration-200 transform hover:scale-105 active:scale-95
                       shadow-lg hover:shadow-xl"
            >
              <Check className="h-5 w-5" />
              Save Information
            </button>
          </div>
        </motion.form>
      </div>
    </div>
  );
};

export default ClientForm;
